import{_ as o,c as r,o as t,ax as i}from"./chunks/framework.DHqKNX4U.js";const u=JSON.parse('{"title":"Merging Ingestion Sources","description":"","frontmatter":{},"headers":[],"relativePath":"user-guides/email-providers/merging-sources.md","filePath":"user-guides/email-providers/merging-sources.md"}'),n={name:"user-guides/email-providers/merging-sources.md"};function a(s,e,l,c,d,h){return t(),r("div",null,e[0]||(e[0]=[i('<h1 id="merging-ingestion-sources" tabindex="-1">Merging Ingestion Sources <a class="header-anchor" href="#merging-ingestion-sources" aria-label="Permalink to &quot;Merging Ingestion Sources&quot;">â€‹</a></h1><p>Merged ingestion groups let you combine multiple ingestion sources so that their emails appear unified in browsing, search, and thread views. This is useful when you want to pair a historical archive (for example, a PST or Mbox import) with a live connection, or when migrating between providers.</p><h2 id="concepts" tabindex="-1">Concepts <a class="header-anchor" href="#concepts" aria-label="Permalink to &quot;Concepts&quot;">â€‹</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Root source</strong></td><td>An ingestion source where no merge parent is set. Shown as the primary row in the Ingestions table. All emails in the group are physically owned by the root.</td></tr><tr><td><strong>Child source</strong></td><td>An ingestion source merged into a root. Acts as a fetch assistant â€” it connects to the provider and retrieves emails, but all data is stored under the root source.</td></tr><tr><td><strong>Group</strong></td><td>A root source and all its children. All emails from every member are stored under and owned by the root.</td></tr></tbody></table><p>The hierarchy is <strong>flat</strong> â€” only one level of nesting is supported. If you merge a source into a child, the system automatically redirects the relationship to the root.</p><h2 id="root-ownership-â€”-how-storage-and-data-work" tabindex="-1">Root Ownership â€” How Storage and Data Work <a class="header-anchor" href="#root-ownership-â€”-how-storage-and-data-work" aria-label="Permalink to &quot;Root Ownership â€” How Storage and Data Work&quot;">â€‹</a></h2><p>This is the key design principle of merged sources:</p><blockquote><p><strong>Child sources are assistants. They fetch emails from their provider but never own any stored data. Every email ingested by a child is written to the root source&#39;s storage folder and assigned the root source&#39;s ID in the database.</strong></p></blockquote><p>In practical terms:</p><ul><li>The storage path for every email belongs to the root: <code>openarchiver/{root-name}-{root-id}/emails/...</code></li><li>Every <code>archived_emails</code> database row created by a child ingestion will have <code>ingestionSourceId</code> set to the <strong>root&#39;s ID</strong>, not the child&#39;s.</li><li>Attachments are also stored under the root&#39;s folder and scoped to the root&#39;s ID.</li><li>The root&#39;s <strong>Preserve Original File</strong> (GoBD compliance) setting is inherited by all children in the group. A child&#39;s own <code>preserveOriginalFile</code> setting is ignored during ingestion â€” only the root&#39;s setting applies.</li></ul><p>This means browsing the root source&#39;s emails will show all emails from the entire group, including those fetched by child sources, without any extra configuration.</p><h2 id="when-to-use-merged-sources" tabindex="-1">When to Use Merged Sources <a class="header-anchor" href="#when-to-use-merged-sources" aria-label="Permalink to &quot;When to Use Merged Sources&quot;">â€‹</a></h2><ul><li><strong>Historical + live</strong>: Import a PST archive and merge it into an active IMAP or Google Workspace connection so historical and current emails appear in one unified mailbox.</li><li><strong>Provider migration</strong>: Add a new Microsoft 365 connector and merge it with your existing Google Workspace connector during a cutover period.</li><li><strong>Backfill</strong>: Import an Mbox export and merge it with a live connection to cover a gap in the archive.</li></ul><h2 id="how-to-merge-a-new-source-into-an-existing-one" tabindex="-1">How to Merge a New Source Into an Existing One <a class="header-anchor" href="#how-to-merge-a-new-source-into-an-existing-one" aria-label="Permalink to &quot;How to Merge a New Source Into an Existing One&quot;">â€‹</a></h2><p>Merging can only be configured <strong>at creation time</strong>.</p><ol><li>Navigate to the <strong>Ingestions</strong> page.</li><li>Click <strong>Create New</strong> to open the ingestion source form.</li><li>Fill in the provider details as usual.</li><li>Expand the <strong>Advanced Options</strong> section at the bottom of the form. This section is only visible when at least one ingestion source already exists.</li><li>Check <strong>Merge into existing ingestion</strong> and select the target root source from the dropdown.</li><li>Click <strong>Submit</strong>.</li></ol><p>The new source will run its initial import normally. Once complete, its emails will appear alongside those of the root source â€” all stored under the root.</p><h2 id="how-emails-appear-when-merged" tabindex="-1">How Emails Appear When Merged <a class="header-anchor" href="#how-emails-appear-when-merged" aria-label="Permalink to &quot;How Emails Appear When Merged&quot;">â€‹</a></h2><p>When you browse archived emails for a root source, you see all emails in the group because they are all physically owned by the root. There is nothing to aggregate â€” the data is already unified at the storage and database level.</p><p>The same applies to search: filtering by a root source ID returns all emails in the group.</p><p>Threads also span the merge group. If a reply arrived via a different source than the original message, it still appears in the correct thread.</p><h2 id="how-syncing-works" tabindex="-1">How Syncing Works <a class="header-anchor" href="#how-syncing-works" aria-label="Permalink to &quot;How Syncing Works&quot;">â€‹</a></h2><p>Each source syncs <strong>independently</strong>. The scheduler picks up all sources with status <code>active</code> or <code>error</code>, regardless of whether they are merged.</p><ul><li>File-based imports (PST, EML, Mbox) finish with status <code>imported</code> and are never re-synced automatically.</li><li>Live sources (IMAP, Google Workspace, Microsoft 365) continue their normal sync cycle.</li></ul><p>When you trigger <strong>Force Sync</strong> on a root source, the system also queues a sync for all non-file-based children that are currently <code>active</code> or <code>error</code>.</p><h2 id="deduplication-across-the-group" tabindex="-1">Deduplication Across the Group <a class="header-anchor" href="#deduplication-across-the-group" aria-label="Permalink to &quot;Deduplication Across the Group&quot;">â€‹</a></h2><p>When ingesting emails, duplicate detection covers the <strong>entire merge group</strong>. If the same email (matched by its RFC <code>Message-ID</code> header or provider-specific ID) already exists anywhere in the group, it is skipped and not stored again.</p><h2 id="preserve-original-file-gobd-compliance-and-merged-sources" tabindex="-1">Preserve Original File (GoBD Compliance) and Merged Sources <a class="header-anchor" href="#preserve-original-file-gobd-compliance-and-merged-sources" aria-label="Permalink to &quot;Preserve Original File (GoBD Compliance) and Merged Sources&quot;">â€‹</a></h2><p>The <strong>Preserve Original File</strong> setting on the root source governs the entire group. When this setting is enabled on the root:</p><ul><li>All emails ingested by child sources are also stored unmodified (raw EML, no attachment stripping).</li><li>The child&#39;s own <code>preserveOriginalFile</code> setting has no effect â€” the root&#39;s setting is always used.</li></ul><p>This ensures consistent compliance behaviour across the group. If you require GoBD or SEC 17a-4 compliance for an entire merged group, enable <strong>Preserve Original File</strong> on the root source before adding any children.</p><h2 id="editing-sources-in-a-group" tabindex="-1">Editing Sources in a Group <a class="header-anchor" href="#editing-sources-in-a-group" aria-label="Permalink to &quot;Editing Sources in a Group&quot;">â€‹</a></h2><p>Each source in a group can be edited independently. Expand the group row in the Ingestions table by clicking the chevron, then use the <strong>â‹®</strong> actions menu on the specific source (root or child) you want to edit.</p><h2 id="unmerging-a-child-source" tabindex="-1">Unmerging a Child Source <a class="header-anchor" href="#unmerging-a-child-source" aria-label="Permalink to &quot;Unmerging a Child Source&quot;">â€‹</a></h2><p>To detach a child from its group and make it standalone:</p><ol><li>Expand the group row by clicking the chevron next to the root source name.</li><li>Open the <strong>â‹®</strong> actions menu on the child source.</li><li>Click <strong>Unmerge</strong>.</li></ol><p>The child becomes an independent root source. No email data is moved or deleted.</p><blockquote><p><strong>Note:</strong> Because all emails fetched by the child were stored under the root source&#39;s ID, unmerging the child does not transfer those emails. Historical emails ingested while the source was a child remain owned by the root. Only new emails ingested after unmerging will be stored under the (now standalone) child.</p></blockquote><h2 id="deleting-sources-in-a-group" tabindex="-1">Deleting Sources in a Group <a class="header-anchor" href="#deleting-sources-in-a-group" aria-label="Permalink to &quot;Deleting Sources in a Group&quot;">â€‹</a></h2><ul><li><strong>Deleting a root source</strong> also deletes all its children: their configuration, and all emails, attachments, storage files, and search index entries owned by the root are all removed. Because all group emails are stored under the root, this effectively removes the entire group&#39;s archive.</li><li><strong>Deleting a child source</strong> removes only the child&#39;s configuration and sync state. Emails already ingested by the child are stored under the root and are <strong>not</strong> deleted.</li></ul><p>A warning is shown in the delete confirmation dialog when a root source has children.</p><h2 id="known-limitations" tabindex="-1">Known Limitations <a class="header-anchor" href="#known-limitations" aria-label="Permalink to &quot;Known Limitations&quot;">â€‹</a></h2><ul><li><strong>Merging existing standalone sources is not supported.</strong> You can only merge a source into a group at creation time. To merge two existing sources, you must delete one and recreate it with the merge target selected.</li><li><strong>Historical data from a child source before unmerging remains with the root.</strong> If you unmerge a child, emails it previously ingested stay owned by the root and are not migrated to the child.</li></ul>',43)]))}const p=o(n,[["render",a]]);export{u as __pageData,p as default};
